var DB={
  q:JSON.parse(localStorage.getItem('hr_q')||'[]'),
  j:JSON.parse(localStorage.getItem('hr_j')||'[]'),
  t:JSON.parse(localStorage.getItem('hr_t')||'[]'),
  // ── ETAPA 1: Central de Contratos ──────────────────────────────────────
  // DB.c armazena SNAPSHOTS FIXOS dos contratos no momento do fechamento.
  // Após salvar, os dados NÃO dependem mais de pendQ, da tela atual nem
  // do histórico de orçamentos — são imutáveis e autocontidos.
  c:JSON.parse(localStorage.getItem('hr_c')||'[]'),
  // ───────────────────────────────────────────────────────────────────────
  sv:function(){
    localStorage.setItem('hr_q',JSON.stringify(this.q));
    localStorage.setItem('hr_j',JSON.stringify(this.j));
    localStorage.setItem('hr_t',JSON.stringify(this.t));
    localStorage.setItem('hr_c',JSON.stringify(this.c)); // ETAPA 1
    SYNC.push();
  }
};
var CFG=JSON.parse(localStorage.getItem('hr_cfg')||'null');

// ═══ SYNC (Supabase — auto sempre ativo) ═══
var SYNC={
  SUPABASE_URL:'https://rdqvjohsxiydcdigygvn.supabase.co',
  SUPABASE_KEY:'sb_publishable_TxqiXyBNdlePn1d1dFzVug_DjcpKAKp',
  CHAVE:'hr_marmores_granitos', // chave única da empresa no banco
  on:false,
  _debounce:null,
  _lastPull:0,
  _channel:null,

  _headers:function(){
    return {
      'Content-Type':'application/json',
      'apikey':this.SUPABASE_KEY,
      'Authorization':'Bearer '+this.SUPABASE_KEY,
      'Prefer':'return=minimal'
    };
  },

  init:function(){
    var self=this;
    // Carrega biblioteca supabase-js via CDN se ainda não carregou
    if(typeof window.supabase!=='undefined'){
      self._connect();
      return;
    }
    var s=document.createElement('script');
    s.src='https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.min.js';
    s.onload=function(){ self._connect(); };
    s.onerror=function(){ self._pullHTTP(); }; // fallback sem realtime
    document.head.appendChild(s);
  },

  _connect:function(){
    var self=this;
    try{
      var sb=window.supabase.createClient(self.SUPABASE_URL, self.SUPABASE_KEY);
      self._sb=sb;
      self.on=true;
      // Pull imediato ao abrir
      self._pullHTTP();
      // Realtime: escuta mudanças na tabela hr_sync
      if(self._channel)try{sb.removeChannel(self._channel);}catch(e){}
      self._channel=sb.channel('hr_sync_changes')
        .on('postgres_changes',{event:'UPDATE',schema:'public',table:'hr_sync',filter:'codigo=eq.'+self.CHAVE},
          function(payload){
            var d=payload.new;
            if(!d||!d.ts)return;
            var localTs=+localStorage.getItem('hr_sync_ts')||0;
            if(d.ts>localTs+1500){
              self._applyRemote(d);
            }
          })
        .subscribe();
    }catch(e){ self._pullHTTP(); }
  },

  _pullHTTP:function(){
    var self=this;
    var url=self.SUPABASE_URL+'/rest/v1/hr_sync?codigo=eq.'+encodeURIComponent(self.CHAVE)+'&select=dados,ts';
    fetch(url,{headers:self._headers()})
      .then(function(r){return r.json();})
      .then(function(rows){
        if(!rows||!rows.length)return;
        var row=rows[0];
        var localTs=+localStorage.getItem('hr_sync_ts')||0;
        if(row.ts>localTs+1500){
          self._applyRemote(row);
        }
      }).catch(function(){});
  },

  _applyRemote:function(row){
    try{
      var d=JSON.parse(row.dados);
      if(d.cfg){CFG=d.cfg;localStorage.setItem('hr_cfg',JSON.stringify(CFG));}
      if(d.q)DB.q=d.q;
      if(d.j)DB.j=d.j;
      if(d.t)DB.t=d.t;
      if(d.c)DB.c=d.c; // ETAPA 1: contratos
      localStorage.setItem('hr_q',JSON.stringify(DB.q));
      localStorage.setItem('hr_j',JSON.stringify(DB.j));
      localStorage.setItem('hr_t',JSON.stringify(DB.t));
      localStorage.setItem('hr_c',JSON.stringify(DB.c)); // ETAPA 1
      localStorage.setItem('hr_sync_ts',row.ts);
      this._lastPull=row.ts;
      // Atualiza UI
      try{buildMat();}catch(e){}
      try{buildSV();}catch(e){}
      try{buildCatalog();}catch(e){}
      try{buildCubaList();}catch(e){}
      try{renderAg();}catch(e){}
      try{renderFin();}catch(e){}
      try{updEmp();}catch(e){}
      try{renderOrc();}catch(e){}
    }catch(e){}
  },

  push:function(){
    var self=this;
    // Debounce: aguarda 800ms de silêncio antes de enviar
    clearTimeout(self._debounce);
    self._debounce=setTimeout(function(){
      self._doPush();
    },800);
  },

  _doPush:function(){
    var self=this;
    var ts=Date.now();
    localStorage.setItem('hr_sync_ts',ts);
    var payload={cfg:CFG,q:DB.q,j:DB.j,t:DB.t,c:DB.c}; // ETAPA 1: inclui contratos
    var body=JSON.stringify({codigo:self.CHAVE,dados:JSON.stringify(payload),ts:ts});
    var url=self.SUPABASE_URL+'/rest/v1/hr_sync';
    var headers=Object.assign({},self._headers(),{'Prefer':'resolution=merge-duplicates,return=minimal'});
    fetch(url,{method:'POST',headers:headers,body:body})
      .then(function(r){
        if(!r.ok)throw new Error(r.status);
      })
      .catch(function(){
        // tenta upsert via PATCH se POST falhou
        fetch(url+'?codigo=eq.'+encodeURIComponent(self.CHAVE),
          {method:'PATCH',headers:self._headers(),body:JSON.stringify({dados:JSON.stringify(payload),ts:ts})})
          .catch(function(){});
      });
  },

  // Chamado quando usuário quer ver status
  status:function(){
    if(!navigator.onLine)return '📵 Sem internet — dados salvos localmente';
    return this.on?'☁️ Sincronização automática ativa':'⏳ Conectando...';
  }
};

